properties.query:
let RecentIngestion = union isfuzzy=true (MDETVM_CL | where TimeGenerated > ago(1d) | summarize Rows = count()), (datatable(Rows:long)[long(0)]) | summarize Rows = sum(Rows);
let RecentKEVAlerts = union isfuzzy=true (SecurityAlert | where TimeGenerated > ago(3d) | where AlertName has 'KEV' | summarize KEVAlerts = count()), (datatable(KEVAlerts:long)[long(0)]) | summarize KEVAlerts = sum(KEVAlerts);
RecentIngestion
| extend KEVAlerts = toscalar(RecentKEVAlerts | project KEVAlerts)
| where Rows > 0 and KEVAlerts == 0
| project Rows, KEVAlerts
